mapper.select:
select f1.oobj_guid from STANDARDIZE_OUTPUTOBJECT f1 inner join STANDARDIZE_OBJECT f2 on  f1.obj_guid = f2.obj_guid
where UPPER(f2.OBJ_ENGNAME) = UPPER(#{outputTableId})
and  f2.SYS_ID=#{sysId} and f2.SYS_SOURCE=#{ownerFactoryNum}

select f1.IOBJ_GUID from STANDARDIZE_INPUTOBJECT f1 inner join STANDARDIZE_OBJECT f2
    on  f1.obj_guid = f2.obj_guid
    where UPPER(f2.OBJ_ENGNAME) = UPPER(#{inputDataId})
       and f2.sys_id = #{inputSourceCode}
       and f1.IOBJ_SOURCE=#{inputSourceFirm,jdbcType=INTEGER}

select max(decode(typeName, 'used', oneCount, 0)) as usedCount,
   max(decode(typeName, 'disableUsed', oneCount, 0)) as disableUsedCount from(
   select 'used'  as typeName, count(*) as oneCount from STANDARDIZE_INPUTOBJECTRELATE
   where IOBJ_GUID = #{inputGuid}
    and OOBJ_GUID = #{outputGuid}
    and  IOR_SOURCE=#{inputIobjSource} and IOR_STATUS = 1
   union ALL
   select 'disableUsed'  as typeName, count(*) as oneCount from STANDARDIZE_INPUTOBJECTRELATE
   where IOBJ_GUID = #{inputGuid}
    and OOBJ_GUID = #{outputGuid}
    and  IOR_SOURCE= #{inputIobjSource} and IOR_STATUS = 0
   )

mapper.insert:
insert into STANDARDIZE_object(SYS_ID , OBJ_ENGNAME , OBJ_CHINAME , SYS_SOURCE,DATA_ID,CENTER_ID,obj_memo) VALUES(
  #{codeTextTd} ,#{tableId} , #{dataSourceName} ,#{ownerFactory},#{dataId},#{centerId},#{objMemo}
)

mapper.update:
  update synlte.OBJECT set OBJECTNAME = #{dataSourceName} , OBJECTSTATE =#{storageTableStatus}
    , TABLENAME =#{realTablename} , STORETYPE =#{storageDataMode,jdbcType=VARCHAR} ,DATA_SOURCE=#{codeTextTd}
    , sourceid = #{sourceId} , OBJECTMEMO = #{objectMemo,jdbcType=VARCHAR} ,HIVETABLENAME=#{realTablename},
    DATATYPE = #{dataType,jdbcType=INTEGER}, OBJECTFLAG = 1, HD_DBSOURCE = 'JZ_RESOURCE',DBSOURCE = 'JZ_RESOURCE',
    ISACTIVETABLE = #{isActiveTable},UPDATETIME = CURRENT_DATE,
    UPDATER = #{updater},CREATOR = #{creator},VERSION=#{version},SECRETLEVEL=#{dataLevel},SJZYBQ1=#{sjzybq1,jdbcType=VARCHAR},
    SJZYBQ2=#{sjzybq2,jdbcType=VARCHAR},SJZYBQ3=#{sjzybq3,jdbcType=VARCHAR},SJZYBQ4=#{sjzybq4,jdbcType=VARCHAR},
    SJZYBQ5=#{sjzybq5,jdbcType=VARCHAR},SJZYBQ6=#{sjzybq6,jdbcType=VARCHAR},STANDARD_TYPE=#{standardType,jdbcType=INTEGER},SJZZYJFLVALLUE=#{SJZZYJFLVALLUE,jdbcType=VARCHAR},
    SJZZEJFLVALUE=#{SJZZEJFLVALUE,jdbcType=VARCHAR},SJZYLYLXVALUE=#{SJZYLYLXVALUE,jdbcType=VARCHAR}
where UPPER(OBJECTID)=UPPER(#{objectId})

update.if:
update synlte.OBJECT set OBJECTNAME = #{dataSourceName} , OBJECTSTATE =#{storageTableStatus}, OBJECTMEMO = #{objectMemo,jdbcType=VARCHAR}
, sourceid = #{sourceId},TABLENAME =#{realTablename} , STORETYPE =#{storageDataMode} , DATA_SOURCE=#{codeTextTd},
ISACTIVETABLE = #{isActiveTable},SJZYBQ1=#{sjzybq1,jdbcType=VARCHAR},SJZYBQ2=#{sjzybq2,jdbcType=VARCHAR},
SJZYBQ3=#{sjzybq3,jdbcType=VARCHAR},SJZYBQ4=#{sjzybq4,jdbcType=VARCHAR},SJZYBQ5=#{sjzybq5,jdbcType=VARCHAR},SJZYBQ6=#{sjzybq6,jdbcType=VARCHAR}
SJZZYJFLVALLUE=#{SJZZYJFLVALLUE,jdbcType=VARCHAR},SJZZEJFLVALUE=#{SJZZEJFLVALUE,jdbcType=VARCHAR},SJZYLYLXVALUE=#{SJZYLYLXVALUE,jdbcType=VARCHAR},
STANDARD_TYPE=#{standardType} where upper(TABLEID)=upper(#{tableId})

update synlte.OBJECT set OBJECTNAME = #{dataSourceName} , OBJECTSTATE =#{storageTableStatus},OBJECTMEMO = #{objectMemo,jdbcType=VARCHAR}
, sourceid = #{sourceId} , STORETYPE =#{storageDataMode},
ISACTIVETABLE = #{isActiveTable} where upper(TABLEID)=upper(#{tableId})

